import React, { useState, useEffect, useRef } from 'react';
import { Timeline } from './components/Timeline';
import { Controls } from './components/Controls';
import { PracticePad } from './components/PracticePad';
import { PlayState, Note, ToolOption, PracticeState, TapResult, TimeSignature } from './types';
import { audioEngine } from './services/audioEngine';
import { generateRhythm } from './services/geminiService';
import { Loader2, Music4, Globe, Moon, Sun } from 'lucide-react';

type Language = 'en' | 'zh';
type Theme = 'light' | 'dark';

const TRANSLATIONS = {
  en: {
    subtitle: "Rhythmic Flow",
    timeSig: "Time Sig",
    palette: "Note Palette",
    timeline: "Visual Timeline",
    measure: "Measure",
