  { id: 'quarter', name: 'Quarter Note', beats: 1, isRest: false, symbol: '♩' },
  { id: 'dotted-quarter', name: 'Dotted Quarter', beats: 1.5, isRest: false, symbol: '♩.' },
  { id: 'eighth', name: 'Eighth Note', beats: 0.5, isRest: false, symbol: '♪' },
  { id: 'dotted-eighth', name: 'Dotted Eighth', beats: 0.75, isRest: false, symbol: '♪.' },
  { id: 'sixteenth', name: '16th Note', beats: 0.25, isRest: false, symbol: '𝅘𝅥𝅯' },
  { id: 'rest-quarter', name: 'Quarter Rest', beats: 1, isRest: true, symbol: '𝄽' },
  { id: 'rest-eighth', name: 'Eighth Rest', beats: 0.5, isRest: true, symbol: '𝄾' },
  { id: 'rest-sixteenth', name: '16th Rest', beats: 0.25, isRest: true, symbol: '𝄿' },
];

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('zh');
  const [theme, setTheme] = useState<Theme>('light');
  const t = TRANSLATIONS[lang];

  const [playState, setPlayState] = useState<PlayState>(PlayState.STOPPED);
  const [bpm, setBpm] = useState<number>(100);
  const [timeSignature, setTimeSignature] = useState<TimeSignature>({ numerator: 4, denominator: 4 });

  // Multi-track state
  const [tracks, setTracks] = useState<Track[]>([
    {
      id: '1',
      name: 'Track 1',
      notes: [
        { id: '1-1', start: 0.0, duration: 0.25, pitch: 1200, velocity: 1.0 }, 
        { id: '1-2', start: 0.25, duration: 0.25, pitch: 800, velocity: 0.8 },
        { id: '1-3', start: 0.5, duration: 0.25, pitch: 800, velocity: 0.8 },
        { id: '1-4', start: 0.75, duration: 0.25, pitch: 800, velocity: 0.8 },
      ]
    }
  ]);
  const [activeTrackId, setActiveTrackId] = useState<string>('1');

  const [progress, setProgress] = useState(0);
  const prevProgressRef = useRef(0);

  const [isGenerating, setIsGenerating] = useState(false);
  const [showGenModal, setShowGenModal] = useState(false);
  const [genPrompt, setGenPrompt] = useState("");

  // Practice Mode State
  const [isPracticeMode, setIsPracticeMode] = useState(false);
  const [practiceState, setPracticeState] = useState<PracticeState>(PracticeState.IDLE);
  const [tapResults, setTapResults] = useState<TapResult[]>([]);

  // Tool Selection State
  const [selectedTool, setSelectedTool] = useState<ToolOption>(TOOLS[0]);

  // Derived: Flatten all notes for AudioEngine and PracticePad
  const allNotes = useMemo(() => {
    return tracks.flatMap(t => t.notes);
  }, [tracks]);

  // Handle Theme Change
  useEffect(() => {
    if (theme === 'dark') {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Sync state with audio engine
  useEffect(() => {
    audioEngine.setNotes(allNotes);
    audioEngine.setBpm(bpm);
    audioEngine.setTimeSignature(timeSignature.numerator);
  }, [allNotes, bpm, timeSignature]);

  // Handle Playback Loop & Practice Logic
  useEffect(() => {
    audioEngine.setOnTick((p) => {
      setProgress((currentProgress) => {
        // DETECT MEASURE WRAP (Loop)
        if (prevProgressRef.current > 0.9 && p < 0.1) {
            // Measure Wrapped
            if (practiceState === PracticeState.DEMO) {
                // End of Demo -> Start Active Mode
                setPracticeState(PracticeState.ACTIVE);
            }
        }
        prevProgressRef.current = p;
        return p;
      });
    });
  }, [practiceState]); 

  const togglePlay = () => {
    if (playState === PlayState.STOPPED) {
      audioEngine.start();
      setPlayState(PlayState.PLAYING);
    } else {
      audioEngine.stop();
      setPlayState(PlayState.STOPPED);
      setProgress(0);
      prevProgressRef.current = 0;

      if (isPracticeMode) {
        setPracticeState(PracticeState.IDLE);
      }
    }
  };

  const handleAddTrack = () => {
    const newId = Math.random().toString(36).substring(7);
    const newTrack: Track = {
      id: newId,
      name: `Track ${tracks.length + 1}`,
      notes: []
    };
    setTracks([...tracks, newTrack]);
    setActiveTrackId(newId);
  };

  const handleRemoveTrack = (id: string) => {
    if (tracks.length <= 1) return; // Prevent deleting last track
    const newTracks = tracks.filter(t => t.id !== id);
    setTracks(newTracks);
    if (activeTrackId === id) {
      setActiveTrackId(newTracks[0].id);
    }
  };

  // Fixed: Support functional updates to prevent "notes.map is not a function" errors
  const handleUpdateTrackNotes = (trackId: string, update: Note[] | ((prev: Note[]) => Note[])) => {
    setTracks(prevTracks => prevTracks.map(track => {
      if (track.id !== trackId) return track;

      const newNotes = typeof update === 'function' 
        ? (update as (prev: Note[]) => Note[])(track.notes)
        : update;

      return { ...track, notes: newNotes };
    }));
  };

  const handleGenerate = async () => {
    if (!genPrompt.trim()) return;
    setIsGenerating(true);
    const newNotes = await generateRhythm(genPrompt, bpm);
    setIsGenerating(false);
    setShowGenModal(false);
    if (newNotes && newNotes.length > 0) {
      handleUpdateTrackNotes(activeTrackId, newNotes);
    }
  };

  const handleStartPractice = () => {
      setTapResults([]); 
      audioEngine.stop();
      setProgress(0);
      prevProgressRef.current = 0;
      setPracticeState(PracticeState.DEMO);
      setPlayState(PlayState.PLAYING);
      audioEngine.start();
  };

  const handleStopPractice = () => {
     audioEngine.stop();
     setPlayState(PlayState.STOPPED);
     setProgress(0);
     prevProgressRef.current = 0;
     setPracticeState(PracticeState.IDLE);
  };

  const handleTogglePracticeMode = () => {
      const nextMode = !isPracticeMode;
      setIsPracticeMode(nextMode);
      audioEngine.stop();
      setPlayState(PlayState.STOPPED);
      setProgress(0);
      prevProgressRef.current = 0;
      setPracticeState(PracticeState.IDLE);
      setTapResults([]);
  };

  const handleTimeSignatureChange = (numerator: number) => {
      audioEngine.stop();
      setPlayState(PlayState.STOPPED);
      setProgress(0);
      setTimeSignature({ numerator, denominator: 4 });
      setTracks(tracks.map(t => ({...t, notes: []})));
  };

  // Logic to append note from palette into the first available gap (from left to right) ON THE ACTIVE TRACK
  const handleAddNoteFromTool = (tool: ToolOption) => {
      setSelectedTool(tool);

      const activeTrack = tracks.find(t => t.id === activeTrackId);
      if (!activeTrack) return;

      const currentNotes = activeTrack.notes;

      // 1. Determine size needed
      const singleDuration = tool.beats / timeSignature.numerator;
      const notesToAdd = 1;
      const totalDurationNeeded = singleDuration * notesToAdd;

      // 2. Find first available gap
      const sortedNotes = [...currentNotes].sort((a, b) => a.start - b.start);
      let insertTime = -1;
      const EPSILON = 0.0001;

      // Check gap at start (0.0 to first note)
      if (sortedNotes.length === 0) {
          if (totalDurationNeeded <= 1.0 + EPSILON) {
              insertTime = 0.0;
          }
      } else {
          // Check space before first note
          if (sortedNotes[0].start >= totalDurationNeeded - EPSILON) {
              insertTime = 0.0;
          }
      }

      // Check gaps between notes
      if (insertTime === -1 && sortedNotes.length > 0) {
          for (let i = 0; i < sortedNotes.length; i++) {
              const currentEnd = sortedNotes[i].start + sortedNotes[i].duration;
              const nextStart = (i === sortedNotes.length - 1) ? 1.0 : sortedNotes[i+1].start;

              if (nextStart - currentEnd >= totalDurationNeeded - EPSILON) {
                  insertTime = currentEnd;
                  break;
              }
          }
      }

      if (insertTime === -1) {
          return; 
      }

      insertTime = Math.round(insertTime * 10000) / 10000;

      // 3. Create Notes
      const newNotesList: Note[] = [];
      for (let i = 0; i < notesToAdd; i++) {
          const noteStart = insertTime + (i * singleDuration);
          if (noteStart + singleDuration > 1.0001) break;

          // Downbeat check
          const isDownbeat = Math.abs(noteStart) < 0.001;
          const pitch = tool.isRest ? 0 : (isDownbeat ? 1200 : 800);
          const velocity = tool.isRest ? 0 : (isDownbeat ? 1.0 : 0.8);

          newNotesList.push({
              id: Math.random().toString(36).substring(7) + '-' + i,
              start: noteStart,
              duration: singleDuration,
              pitch: pitch,
              velocity: velocity,
              isRest: tool.isRest,
              selected: false,
          });
      }

      if (newNotesList.length > 0) {
           handleUpdateTrackNotes(activeTrackId, [...currentNotes, ...newNotesList]);
      }
  };

  const toggleLang = () => {
      setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  const toggleTheme = () => {
      setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-950 text-gray-900 dark:text-gray-100 selection:bg-indigo-100 dark:selection:bg-indigo-900 transition-colors duration-300">

      {/* Header */}
      <header className="px-6 py-4 bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 flex items-center justify-between sticky top-0 z-50 shadow-sm transition-colors duration-300">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-md shadow-indigo-200 dark:shadow-none">
            <Music4 className="text-white" size={24} />
            </div>
            <div>
            <h1 className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">Chronos Flow</h1>
            <p className="text-xs text-gray-500 dark:text-gray-400 font-medium">{t.subtitle}</p>
            </div>
        </div>

        <div className="flex items-center gap-4">
             {/* Theme Toggle */}
             <button
                onClick={toggleTheme}
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
             >
                 {theme === 'light' ? <Moon size={16} /> : <Sun size={16} />}
             </button>

             {/* Language Switch */}
            <button 
                onClick={toggleLang}
                className="flex items-center gap-1 text-xs font-bold text-gray-500 dark:text-gray-400 hover:text-indigo-600 dark:hover:text-indigo-400 px-2 py-1 rounded bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 transition-colors"
            >
                <Globe size={14} />
                {lang === 'zh' ? 'EN' : '中文'}
            </button>

            {/* Time Signature Selector */}
            <div className="flex items-center gap-2 bg-gray-100 dark:bg-gray-800 rounded-lg p-1 border border-gray-200 dark:border-gray-700 transition-colors">
                <span className="text-xs font-bold text-gray-500 dark:text-gray-400 px-2 uppercase">{t.timeSig}</span>
                <select 
                    value={timeSignature.numerator}
                    onChange={(e) => handleTimeSignatureChange(parseInt(e.target.value))}
                    className="bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 text-gray-800 dark:text-gray-200 text-sm rounded-md focus:ring-indigo-500 focus:border-indigo-500 block p-1.5 font-mono font-bold outline-none"
                >
                    <option value={3}>3/4</option>
                    <option value={4}>4/4</option>
                    <option value={5}>5/4</option>
                    <option value={6}>6/4</option>
                    <option value={7}>7/4</option>
                </select>
            </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto p-4 md:p-8 space-y-8">

        {/* Tool Palette */}
        <section className="bg-white dark:bg-gray-900 p-4 rounded-2xl border border-gray-200 dark:border-gray-800 shadow-sm flex flex-col items-start gap-4 transition-colors duration-300">
           <span className="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest pl-1">{t.palette}</span>
           <div className="flex flex-wrap items-center gap-3 w-full">
               {TOOLS.map(tool => (
                   <button
                    key={tool.id}
                    onClick={() => handleAddNoteFromTool(tool)}
                    title={t.tools[tool.id as keyof typeof t.tools]}
                    className={`
                        flex items-center justify-center w-14 h-14 rounded-xl border transition-all relative
                        ${selectedTool.id === tool.id 
                            ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-200 dark:shadow-none ring-2 ring-indigo-100 dark:ring-indigo-900 scale-105' 
                            : 'bg-white dark:bg-gray-800 text-gray-500 dark:text-gray-400 border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-750 hover:border-gray-300 dark:hover:border-gray-600 hover:text-gray-900 dark:hover:text-gray-200'
                        }
                    `}
                   >
                       <span className="text-4xl leading-none font-serif pt-1">{tool.symbol}</span>
                       <span className="absolute bottom-1 right-1 text-[8px] opacity-60 font-mono font-bold">
                           {tool.beats}
                       </span>
                   </button>
               ))}
           </div>
        </section>

        {/* Tracks Area */}
        <section className="space-y-4">
          <div className="flex justify-between items-end px-2">
            <h2 className="text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-widest">{t.timeline}</h2>
            <div className="flex items-center gap-4">
                <button 
                    onClick={handleAddTrack}
                    className="flex items-center gap-1 text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-800 dark:hover:text-indigo-300 transition-colors"
                >
                    <Plus size={14} />
                    {t.addTrack}
                </button>
                <div className="text-xs font-mono text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded transition-colors">
                    {t.measure}: {Math.floor(progress * 100)}%
                </div>
            </div>
          </div>

          <div className="flex flex-col gap-4">
            {tracks.map((track) => (
                <Timeline 
                    key={track.id}
                    trackId={track.id}
                    trackName={track.name}
                    notes={track.notes} 
                    setNotes={(newNotes) => handleUpdateTrackNotes(track.id, newNotes)} 
                    progress={progress} 
                    isPlaying={playState === PlayState.PLAYING} 
                    selectedTool={selectedTool}
                    tapResults={isPracticeMode && activeTrackId === track.id ? tapResults : []} // Show taps only on active track for now
                    timeSignature={timeSignature}
                    isActive={activeTrackId === track.id}
                    onTrackSelect={() => setActiveTrackId(track.id)}
                    onDeleteTrack={() => handleRemoveTrack(track.id)}
                    canDelete={tracks.length > 1}
                />
            ))}
          </div>
        </section>

        {/* Practice Mode Overlay */}
        {isPracticeMode && (
          <section className="animate-in fade-in duration-300">
             <div className="flex justify-between items-end px-2 mb-2">
                <h2 className="text-sm font-semibold text-orange-500 uppercase tracking-widest">{t.practiceTitle}</h2>
             </div>
             <PracticePad 
                notes={allNotes}
                progress={progress}
                isPlaying={playState === PlayState.PLAYING}
                bpm={bpm}
                practiceState={practiceState}
                onStartPractice={handleStartPractice}
                onStopPractice={handleStopPractice}
                onTapResult={(res) => setTapResults(prev => [...prev, res])}
                labels={t.pad}
             />
          </section>
        )}

        {/* Controls Area */}
        <Controls
          playState={playState}
          bpm={bpm}
          onTogglePlay={togglePlay}
          onBpmChange={setBpm}
          onClear={() => setTracks(tracks.map(t => ({...t, notes: []})))}
          onGenerate={() => setShowGenModal(true)}
          isGenerating={isGenerating}
          isPracticeMode={isPracticeMode}
          onTogglePractice={handleTogglePracticeMode}
          labels={t.controls}
        />

        {/* Info / Instructions */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-8 border-t border-gray-200 dark:border-gray-800 transition-colors">
           <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl border border-gray-200 dark:border-gray-800 shadow-sm transition-colors">
             <h3 className="text-lg font-semibold text-gray-800 dark:text-gray-100 mb-2">{t.durationTitle}</h3>
             <p 
                className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed"
                dangerouslySetInnerHTML={{ __html: t.durationDesc }}
             />
           </div>
           <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl border border-gray-200 dark:border-gray-800 shadow-sm transition-colors">
             <h3 className="text-lg font-semibold text-gray-800 dark:text-gray-100 mb-2">{t.practiceInfoTitle}</h3>
             <p 
                className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed"
                dangerouslySetInnerHTML={{ __html: t.practiceInfoDesc }}
             />
           </div>
        </section>
      </main>

      {/* AI Generator Modal */}
      {showGenModal && (
        <div className="fixed inset-0 bg-gray-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-800 w-full max-w-md p-6 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-2xl space-y-4 animate-in fade-in zoom-in duration-200">
            <h2 className="text-xl font-bold text-gray-900 dark:text-white">{t.genModalTitle}</h2>
            <p className="text-gray-500 dark:text-gray-400 text-sm">{t.genModalDesc}</p>

            <textarea
              className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none min-h-[100px] text-gray-800 dark:text-gray-100 placeholder-gray-400 dark:placeholder-gray-500"
              placeholder={t.genPlaceholder}
              value={genPrompt}
              onChange={(e) => setGenPrompt(e.target.value)}
            />

            <div className="flex justify-end gap-3 pt-2">
              <button 
                onClick={() => setShowGenModal(false)}
                className="px-4 py-2 text-sm text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white"
              >
                {t.cancel}
              </button>
              <button 
                onClick={handleGenerate}
                disabled={!genPrompt || isGenerating}
                className="px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-sm font-semibold flex items-center gap-2 disabled:opacity-50 shadow-sm shadow-indigo-200 dark:shadow-none"
              >
                {isGenerating && <Loader2 size={16} className="animate-spin" />}
                {t.generate}
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Note, ToolOption, TapResult, TimeSignature } from '../types';
import { X, Trash2 } from 'lucide-react';

interface TimelineProps {
  trackId: string;
  trackName: string;
  notes: Note[];
  setNotes: (notes: Note[] | ((prev: Note[]) => Note[])) => void;
  progress: number; // 0.0 to 1.0
  isPlaying: boolean;
  selectedTool: ToolOption;
  tapResults?: TapResult[]; 
  timeSignature: TimeSignature;
  measureLabel?: string;
  isActive: boolean;
  onTrackSelect: () => void;
  onDeleteTrack: () => void;
  canDelete: boolean;
}

// Helper to determine symbol based on BEAT length (not percentage)
const getNoteSymbol = (durationPercentage: number, isRest: boolean, numerator: number) => {
  const beats = durationPercentage * numerator;
  const isApprox = (val: number, target: number) => Math.abs(val - target) < 0.1;

  if (isRest) {
    if (isApprox(beats, 1)) return '𝄽';      // Quarter Rest
    if (isApprox(beats, 0.5)) return '𝄾';     // Eighth Rest
    if (isApprox(beats, 0.25)) return '𝄿';    // 16th Rest
    return '𝄽'; 
  }

  if (isApprox(beats, 1.5)) return '♩.';      // Dotted Quarter
  if (isApprox(beats, 1)) return '♩';         // Quarter Note
  if (isApprox(beats, 0.75)) return '♪.';     // Dotted Eighth
  if (isApprox(beats, 0.5)) return '♪';       // Eighth Note
  if (isApprox(beats, 0.25)) return '𝅘𝅥𝅯';      // 16th Note (Single)

  return '♩'; 
};

export const Timeline: React.FC<TimelineProps> = ({ 
    trackId,
    trackName,
    notes, 
    setNotes, 
    progress, 
    isPlaying, 
    selectedTool, 
    tapResults = [],
    timeSignature,
    measureLabel = "Measure",
    isActive,
    onTrackSelect,
    onDeleteTrack,
    canDelete
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  // Ref to access latest notes inside stable callbacks without re-triggering effects
  const notesRef = useRef(notes);
  useEffect(() => {
    notesRef.current = notes;
  }, [notes]);

  const [dragState, setDragState] = useState<{
    noteId: string | null;
    startX: number;
    initialStart: number;
  } | null>(null);

  // Visual Snap Indicator State
  const [snapIndicator, setSnapIndicator] = useState<number | null>(null);

  // Constants for interactions
  const TIMELINE_HEIGHT = 160;

  // Generate Subdivisions based on Time Signature Numerator
  // We want 4 subdivisions (16th notes) per beat.
  // Total subdivisions = numerator * 4.
  const totalSubdivisions = timeSignature.numerator * 4;
  const subdivisions = Array.from({ length: totalSubdivisions }).map((_, i) => i / totalSubdivisions);

  // Magnetic Snap Logic
  // snaps to Grid (1/16) and Adjacent Note Edges
  const getSnapPosition = (rawPos: number, ignoreNoteId: string | null, currentNotes: Note[]) => {
      const SNAP_THRESHOLD = 0.025; 
      const GRID_SIZE = 1 / totalSubdivisions; 

      let bestSnap = rawPos;
      let minDst = SNAP_THRESHOLD;

      // 1. Grid Snapping
      const gridPoint = Math.round(rawPos / GRID_SIZE) * GRID_SIZE;
      if (Math.abs(gridPoint - rawPos) < minDst) {
          minDst = Math.abs(gridPoint - rawPos);
          bestSnap = gridPoint;
      }

      // 2. Adjacent Note Snapping (Start & End)
      currentNotes.forEach(n => {
          if (n.id === ignoreNoteId) return;

          // Snap to Note Start
          const dstStart = Math.abs(n.start - rawPos);
          if (dstStart < minDst) {
              minDst = dstStart;
              bestSnap = n.start;
          }

          // Snap to Note End
          const noteEnd = n.start + n.duration;
          const dstEnd = Math.abs(noteEnd - rawPos);
          if (dstEnd < minDst) {
              minDst = dstEnd;
              bestSnap = noteEnd;
          }
      });

      return bestSnap;
  };

  const handlePointerDown = (e: React.PointerEvent, noteId: string | null) => {
    // Only allow interaction if we select the track first
    onTrackSelect();

    e.preventDefault();
    e.stopPropagation();

    if (!noteId) {
        // Create new note
        const rect = containerRef.current!.getBoundingClientRect();
        const clickX = e.clientX - rect.left;
        const rawStart = Math.min(Math.max(clickX / rect.width, 0), 0.99);

        // MAGNETIC SNAP for Creation
        const snappedStart = getSnapPosition(rawStart, null, notes);

        // Calculate duration based on BEATS vs NUMERATOR
        // e.g., 1 beat in 4/4 is 0.25. 1 beat in 3/4 is 0.33.
        const durationPct = selectedTool.beats / timeSignature.numerator;

        // Clamp to ensure it fits (simple check)
        const finalStart = Math.min(snappedStart, 1.0 - durationPct);

        // Check Downbeat
        const isDownbeat = finalStart < 0.001;
        const pitch = selectedTool.isRest ? 0 : (isDownbeat ? 1200 : 800);
        const velocity = selectedTool.isRest ? 0 : (isDownbeat ? 1.0 : 0.8);

        const newNote: Note = {
            id: Math.random().toString(36).substring(7),
            start: finalStart,
            duration: durationPct,
            pitch: pitch,
            velocity: velocity, 
            isRest: selectedTool.isRest,
            selected: true,
        };
        // Deselect others
        const updated = notes.map(n => ({ ...n, selected: false }));
        setNotes([...updated, newNote]);
        return;
    }

    const note = notes.find(n => n.id === noteId);
    if (!note) return;

    // Deselect others, select this one
    const updated = notes.map(n => ({ ...n, selected: n.id === noteId }));
    setNotes(updated);

    setDragState({
      noteId,
      startX: e.clientX,
      initialStart: note.start,
    });
  };

  const handlePointerMove = useCallback((e: PointerEvent) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const currentNotes = notesRef.current;

    // Find note being dragged to get its duration for clamping
    const note = currentNotes.find(n => n.id === dragState.noteId);
    if (!note) return;

    setNotes(prevNotes => prevNotes.map(n => {
      if (n.id !== dragState.noteId) return n;

      const deltaX = (e.clientX - dragState.startX) / rect.width;
      const rawNewStart = dragState.initialStart + deltaX;

      // Magnetic Snap for Move
      const snappedStart = getSnapPosition(rawNewStart, n.id, currentNotes);
      const clampedStart = Math.max(0, Math.min(1 - n.duration, snappedStart));

      // Visual Snap Feedback Logic
      if (Math.abs(snappedStart - rawNewStart) > 0.001) {
          setSnapIndicator(clampedStart);
      } else {
          setSnapIndicator(null);
      }

      // Update Pitch dynamically if moved to/from downbeat (only if not a rest)
      let nextPitch = n.pitch;
      let nextVelocity = n.velocity;

      if (!n.isRest) {
          const isDownbeat = clampedStart < 0.001;
          nextPitch = isDownbeat ? 1200 : 800;
          nextVelocity = isDownbeat ? 1.0 : 0.8;
      }

      return { ...n, start: clampedStart, pitch: nextPitch, velocity: nextVelocity };
    }));
  }, [dragState, setNotes, timeSignature.numerator]); 

  const handlePointerUp = useCallback(() => {
    setDragState(null);
    setSnapIndicator(null); 
  }, []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
    } else {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    }
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [dragState, handlePointerMove, handlePointerUp]);

  // Handle Note Deletion
  const handleDelete = (id: string, e: React.SyntheticEvent) => {
      e.stopPropagation();
      e.preventDefault();
      setNotes(notes.filter(n => n.id !== id));
  };

  // Generate Beat Labels (1, 2, 3...)
  const beatLabels = Array.from({ length: timeSignature.numerator }).map((_, i) => i + 1);

  return (
    <div 
        className={`
            relative w-full rounded-xl transition-all duration-200 group
            ${isActive 
                ? 'ring-2 ring-indigo-500 bg-white dark:bg-gray-900 shadow-md scale-[1.005]' 
                : 'ring-1 ring-gray-200 dark:ring-gray-800 bg-gray-50/50 dark:bg-gray-900/50 opacity-90 hover:opacity-100 hover:ring-indigo-200'
            }
        `}
        onPointerDown={onTrackSelect}
    >
        {/* Track Header */}
        <div className="flex items-center justify-between px-3 py-2 border-b border-gray-100 dark:border-gray-800">
            <span className={`text-xs font-bold uppercase tracking-wider ${isActive ? 'text-indigo-600 dark:text-indigo-400' : 'text-gray-400'}`}>
                {trackName}
            </span>
            {canDelete && (
                <button 
                    onClick={(e) => { e.stopPropagation(); onDeleteTrack(); }}
                    className="p-1 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded transition-colors"
                >
                    <Trash2 size={14} />
                </button>
            )}
        </div>

      {/* Progress Bar Container */}
      <div 
        ref={containerRef}
        className="relative w-full overflow-hidden cursor-crosshair"
        style={{ height: TIMELINE_HEIGHT }}
        onPointerDown={(e) => handlePointerDown(e, null)}
      >
        {/* Background Grid */}
        {subdivisions.map((pos) => {
            // Is this a beat line? (every 4 subdivisions)
            const isBeatLine = Math.abs((pos * totalSubdivisions) % 4) < 0.1;
            return (
                <div
                    key={pos}
                    className={`absolute top-0 bottom-0 pointer-events-none transition-colors ${
                    isBeatLine 
                        ? 'border-r border-gray-300 dark:border-gray-700 w-[1px]' 
                        : 'border-r border-gray-100 dark:border-gray-800 w-[1px] border-dashed'
                    }`}
                    style={{ left: `${pos * 100}%` }}
                />
            );
        })}

        {/* Snap Indicator Line */}
        {snapIndicator !== null && (
            <div 
                className="absolute top-0 bottom-0 w-[2px] bg-amber-400 z-50 pointer-events-none shadow-[0_0_8px_rgba(251,191,36,0.6)] animate-in fade-in duration-75"
                style={{ left: `${snapIndicator * 100}%` }}
            />
        )}

        {/* Beats Labels */}
        <div className="absolute bottom-1 left-0 w-full flex justify-between px-[1%] pointer-events-none text-gray-400 dark:text-gray-500 font-mono text-xs font-bold z-10 transition-colors">
            {beatLabels.map((beat) => (
                <span key={beat} className="translate-x-1/2">{beat}</span>
            ))}
            <span>|</span>
        </div>

        {/* Notes */}
        {notes.map((note) => {
           const isPlayingNote = isPlaying && progress >= note.start && progress <= (note.start + note.duration);
           const isRest = note.isRest || note.velocity < 0.01;
           const symbol = getNoteSymbol(note.duration, isRest, timeSignature.numerator);

           // Calculate fill width for progress effect
           let fillWidth = '0%';
           if (isPlayingNote) {
               fillWidth = `${((progress - note.start) / note.duration) * 100}%`;
           } else if (progress > (note.start + note.duration)) {
             fillWidth = '0%'; // Reset when passed
           }

           // CSS gradient for hatched pattern that works in light/dark
           const restPatternStyle = {
               backgroundImage: `repeating-linear-gradient(
                   45deg,
                   transparent,
                   transparent 5px,
                   currentColor 5px,
                   currentColor 6px
               )`,
               opacity: 0.1
           };

           return (
            <div
                key={note.id}
                className={`
                    absolute top-1/2 -translate-y-1/2 h-20 rounded-lg shadow-sm
                    flex items-center justify-between overflow-hidden
                    transition-all duration-100 cursor-move
                    ${isRest 
                        ? 'bg-gray-50 dark:bg-gray-900/50 text-gray-400 dark:text-gray-500 border-gray-300 dark:border-gray-700' 
                        : 'bg-white dark:bg-gray-800 text-indigo-500 dark:text-indigo-400 border-indigo-200 dark:border-indigo-700'
                    }
                    ${note.selected ? 'ring-2 ring-indigo-500 z-40' : 'z-20 hover:border-indigo-400 dark:hover:border-indigo-500'}
                    border-2
                `}
                style={{
                    left: `${note.start * 100}%`,
                    width: `${note.duration * 100}%`,
                }}
                onPointerDown={(e) => handlePointerDown(e, note.id)}
            >
                {/* REST PATTERN OVERLAY */}
                {isRest && (
                    <div 
                        className="absolute inset-0 pointer-events-none text-gray-400 dark:text-gray-600"
                        style={restPatternStyle}
                    />
                )}

                {/* PROGRESS FILL BAR */}
                <div 
                    className={`absolute left-0 top-0 bottom-0 pointer-events-none transition-none will-change-[width] border-r-[3px] ${
                        isRest 
                          ? 'bg-gray-600/20 dark:bg-gray-400/20 border-gray-500 dark:border-gray-400' 
                          : 'bg-indigo-600/20 dark:bg-indigo-500/30 border-indigo-600 dark:border-indigo-500'
                    }`}
                    style={{ width: fillWidth }}
                />

                {/* Note Content (Symbol) */}
                <div className="relative z-10 w-full h-full flex items-center justify-center pointer-events-none">
                     <span className={`text-3xl font-serif select-none ${isRest ? 'text-gray-400 dark:text-gray-600' : 'text-indigo-500 dark:text-indigo-400 pb-2'}`}>
                        {symbol}
                     </span>
                </div>

                {/* Delete Button */}
                <button
                    onPointerDown={(e) => handleDelete(note.id, e)}
                    className="absolute top-1 right-1 w-5 h-5 flex items-center justify-center text-gray-400 hover:text-red-500 hover:bg-white hover:shadow-md hover:border-red-100 border border-transparent rounded-full z-50 transition-all bg-white/50 dark:bg-gray-800/50 backdrop-blur-sm"
                    title="Remove Note"
                >
                    <X size={12} strokeWidth={3} />
                </button>
            </div>
          );
        })}

        {/* TAP RESULTS OVERLAY */}
        {tapResults.map((res, index) => {
            const isLatest = index === tapResults.length - 1;
            return (
                <div
                    key={res.id}
                    className={`
                        absolute top-1/2 -translate-y-1/2 rounded-full border-2 border-white dark:border-gray-800 shadow-lg
                        transition-all duration-500 ease-out
                        ${res.isHit ? 'bg-green-500 shadow-green-500/50' : 'bg-red-500 shadow-red-500/50'}
                        ${isLatest 
                            ? 'w-5 h-5 z-50 opacity-100 scale-110 ring-4 ring-white/50 dark:ring-gray-700/50' 
                            : 'w-3 h-3 z-40 opacity-40 grayscale-[0.3]'
                        }
                    `}
                    style={{ left: `calc(${res.location * 100}% - ${isLatest ? 10 : 6}px)` }}
                />
            );
        })}

      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Note } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateRhythm = async (description: string, currentBpm: number): Promise<Note[]> => {
  try {
    const model = 'gemini-2.5-flash';

    const prompt = `
      Create a musical rhythmic pattern loop based on this description: "${description}".
      The loop represents one measure of 4/4 time.
      Return the notes in a JSON format.

      Rules:
      - 'start' is the start time percentage (0.0 to 1.0) within the measure.
      - 'duration' is the length percentage (0.0 to 1.0).
      - 'pitch' is frequency in Hz (use 440, 880, 220, 660 etc for musical intervals).
      - 'velocity' is volume (0.5 to 1.0).
      - Keep durations precise so they don't overlap too messily unless intentional.
      - Typically 4/4 time, so a quarter note is duration 0.25.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              start: { type: Type.NUMBER },
              duration: { type: Type.NUMBER },
              pitch: { type: Type.NUMBER },
              velocity: { type: Type.NUMBER }
            },
            required: ["start", "duration", "pitch", "velocity"]
          }
        }
      }
    });

    let text = response.text || "[]";
    // Clean up markdown if present
    text = text.replace(/```json/g, '').replace(/```/g, '').trim();

    let rawNotes = JSON.parse(text);

    // Handle case where AI wraps array in an object key
    if (!Array.isArray(rawNotes) && typeof rawNotes === 'object' && rawNotes !== null) {
       // Look for any value that is an array
       const arrayVal = Object.values(rawNotes).find(val => Array.isArray(val));
       if (arrayVal) rawNotes = arrayVal;
    }

    if (!Array.isArray(rawNotes)) {
        console.warn("AI response is not an array:", rawNotes);
        return [];
    }

    // Add IDs to the notes
    return rawNotes.map((note: any) => ({
      ...note,
      id: Math.random().toString(36).substring(7),
    }));

  } catch (error) {
    console.error("Error generating rhythm:", error);
    return [];
  }
};

import { Track } from '../types';

// Web Audio API Context singleton
let audioContext: AudioContext | null = null;

// Scheduling constants
const LOOKAHEAD = 25.0; // milliseconds
const SCHEDULE_AHEAD_TIME = 0.1; // seconds

export class AudioEngine {
  private nextNoteTime: number = 0.0;
  private startTime: number = 0.0; // Anchor for visual sync
  private timerID: number | null = null;

  // Changed from flat notes to tracks for sequential playback
  private tracks: Track[] = [];
  private currentScheduleTrackIndex: number = 0; // For the scheduler logic

  private bpm: number = 100;
  private beatsPerMeasure: number = 4; // Default 4/4
  private isPlaying: boolean = false;

  // Track active oscillators to cancel them immediately on stop
  private activeOscillators: OscillatorNode[] = [];

  // Callback for UI updates (passed the current progress 0-1 and current track index)
  private onTick: ((progress: number, trackIndex: number) => void) | null = null;

  constructor() {
    // Lazy load audio context
  }

  private initAudioContext() {
    if (!audioContext) {
      audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  public setTracks(tracks: Track[]) {
    this.tracks = tracks;
  }

  // Deprecated but kept for compatibility if needed, though we use setTracks now
  public setNotes(notes: any[]) {
      // no-op or handle single track
  }

  public setBpm(bpm: number) {
    this.bpm = bpm;
  }

  public setTimeSignature(numerator: number) {
    this.beatsPerMeasure = numerator;
  }

  public setOnTick(callback: (progress: number, trackIndex: number) => void) {
    this.onTick = callback;
  }

  public start() {
    this.initAudioContext();
    if (audioContext?.state === 'suspended') {
      audioContext.resume();
    }

    if (this.isPlaying) return;

    this.isPlaying = true;

    // Reset the timing anchor to NOW. 
    this.startTime = audioContext!.currentTime;
    this.nextNoteTime = this.startTime;

    // Reset scheduler index to start from the first track
    this.currentScheduleTrackIndex = 0;

    this.scheduler();
    this.startAnimationLoop();
  }

  public stop() {
    this.isPlaying = false;
    if (this.timerID) {
      window.clearTimeout(this.timerID);
      this.timerID = null;
    }

    // Immediately stop all scheduled sounds
    this.activeOscillators.forEach((osc) => {
        try {
            osc.stop();
            osc.disconnect();
        } catch (e) {
            // Ignore if already stopped
        }
    });
    this.activeOscillators = [];
  }

  private scheduler() {
    if (!this.isPlaying || !audioContext) return;

    // while there are notes that will need to play before the next interval, 
    // schedule them and advance the pointer.
    while (this.nextNoteTime < audioContext.currentTime + SCHEDULE_AHEAD_TIME) {
      this.scheduleNotesForMeasure(this.nextNoteTime);
      this.advanceNote();
    }

    this.timerID = window.setTimeout(() => this.scheduler(), LOOKAHEAD);
  }

  private advanceNote() {
    // Advance time by a full measure based on Time Signature
    const secondsPerBeat = 60.0 / this.bpm;
    const measureDuration = secondsPerBeat * this.beatsPerMeasure; 

    this.nextNoteTime += measureDuration;

    // Advance to the next track in the sequence
    if (this.tracks.length > 0) {
        this.currentScheduleTrackIndex = (this.currentScheduleTrackIndex + 1) % this.tracks.length;
    } else {
        this.currentScheduleTrackIndex = 0;
    }
  }

  private scheduleNotesForMeasure(time: number) {
    if (!audioContext || this.tracks.length === 0) return;

    const secondsPerBeat = 60.0 / this.bpm;
    const measureDuration = secondsPerBeat * this.beatsPerMeasure;

    // Get notes only for the currently scheduled track
    const currentTrack = this.tracks[this.currentScheduleTrackIndex];
    if (!currentTrack) return;

    const notes = currentTrack.notes;

    notes.forEach(note => {
      // STRICT CHECK: If explicitly a rest or velocity is near zero, do NOT play.
      if (note.isRest === true || note.velocity < 0.01) return;

      // Calculate start time
      const noteStartTime = time + (note.start * measureDuration);

      const osc = audioContext!.createOscillator();
      const gainNode = audioContext!.createGain();

      osc.connect(gainNode);
      gainNode.connect(audioContext!.destination);

      // Sound Design: "Modern Digital Click"
      osc.type = 'sine'; 

      // Pitch Envelope
      const startFreq = note.pitch;
      osc.frequency.setValueAtTime(startFreq, noteStartTime);
      osc.frequency.exponentialRampToValueAtTime(Math.max(100, startFreq * 0.9), noteStartTime + 0.05);

      // Amplitude Envelope
      gainNode.gain.setValueAtTime(0, noteStartTime);
      gainNode.gain.linearRampToValueAtTime(note.velocity, noteStartTime + 0.001);

      // Decay
      const clickDuration = 0.08; 
      gainNode.gain.exponentialRampToValueAtTime(0.001, noteStartTime + clickDuration);

      // Track the oscillator
      osc.onended = () => {
          const index = this.activeOscillators.indexOf(osc);
          if (index > -1) {
              this.activeOscillators.splice(index, 1);
          }
      };
      this.activeOscillators.push(osc);

      osc.start(noteStartTime);
      osc.stop(noteStartTime + clickDuration + 0.05); // Cleanup
    });
  }

  private startAnimationLoop() {
    if (!audioContext) return;

    const loop = () => {
      if (!this.isPlaying) return;

      const secondsPerBeat = 60.0 / this.bpm;
      const measureDuration = secondsPerBeat * this.beatsPerMeasure;
      const numTracks = this.tracks.length || 1;

      // Calculate global time since start
      const timeSinceStart = audioContext!.currentTime - this.startTime;

      // Determine which measure index (absolute) we are in
      const absoluteMeasureIndex = Math.floor(timeSinceStart / measureDuration);

      // Map absolute measure to track index (looping)
      const currentTrackIndex = absoluteMeasureIndex % numTracks;

      // Calculate progress within that specific measure (0.0 to 1.0)
      const currentCycleTime = timeSinceStart % measureDuration;
      const progress = currentCycleTime / measureDuration;

      if (this.onTick) {
        this.onTick(progress, currentTrackIndex);
      }

      requestAnimationFrame(loop);
    };
    loop();
  }
}

