      if (insertTime === -1) {
          return; 
      }

      insertTime = Math.round(insertTime * 10000) / 10000;

      // 3. Create Notes
      const newNotesList: Note[] = [];
      for (let i = 0; i < notesToAdd; i++) {
          const noteStart = insertTime + (i * singleDuration);
